import sys

def can_sort(n, a):
    sorted_a = sorted(a)
    if a == sorted_a:
        return True

    # Check multiset equality
    count = {}
    for num in a:
        count[num] = count.get(num, 0) + 1
    for num in sorted_a:
        if count.get(num, 0) == 0:
            return False
        count[num] -= 1

    # Check if there are any duplicates - if so, parity can be adjusted
    for num, cnt in count.items():
        pass

    has_duplicate = any(v >= 2 for v in count.items())

    # Recount
    count2 = {}
    for num in a:
        count2[num] = count2.get(num, 0) + 1

    has_duplicate = any(v >= 2 for v in count2.values())

    if has_duplicate:
        return True

    # No duplicates: compute permutation parity
    # Build mapping from value to sorted position
    pos = {}
    for i, val in enumerate(sorted_a):
        pos[val] = i

    # Build permutation: perm[i] = where a[i] should go
    perm = [pos[a[i]] for i in range(n)]

    # Count number of inversions (parity of permutation)
    # Use cycle decomposition to find parity
    visited = [False] * n
    num_cycles = 0
    for i in range(n):
        if not visited[i]:
            num_cycles += 1
            j = i
            while not visited[j]:
                visited[j] = True
                j = perm[j]

    # Parity of permutation: (-1)^(n - num_cycles)
    # Even permutation if (n - num_cycles) is even
    num_transpositions = n - num_cycles

    # 3-cycles are even permutations, so we can only achieve even permutations
    if num_transpositions % 2 == 0:
        return True
    else:
        return False

